93	const INSURANCE_VALUES: Record<string, number> = {
94	  sword: 1000,
95	  amulet: 600,
96	  staff: 800,
97	  potion: 400,
98	  rune: 250,
99	  moonstone: 250,
100	};
101	const DEDUCTIBLE = 100;
102	const CAP_MULTIPLIER = 2;
103	
104	export function claim(policy: Policy, incident: Incident, _remainingCap: number): ClaimResult {
105	  const damage = incident.damages[0];
106	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
107	  const reimbursable =
108	    (damagedItem?.enchantment ?? 0) >= 8 ? damage.amount / 2 : damage.amount;
109	  const payout = reimbursable - DEDUCTIBLE;
110	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
111	  const remainingCap = CAP_MULTIPLIER * insuranceSum - payout;
112	  return { payout, remainingCap };
113	}
114	
115	export function quote(customer: Customer, items: Item[], options?: QuoteOptions): number {
116	  const baseTotal = policyBaseTotal(items);
117	  const surchargeTotal = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
118	  const firstInsurance = baseTotal * FIRST_INSURANCE_RATE;
119	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT : 0;
120	  const followUpDiscount = options?.isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
121	  const premium =
122	    baseTotal + surchargeTotal + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
123	  return Math.ceil(premium);
124	}
